public class Solution {
    public boolean isMatch(String s, String p) {
        int m = s.length(), n = p.length();
        int i = 0, j = 0, asterisk = -1, match = 0;
        while (i < m) {
            if (j < n && (s.charAt(i) == p.charAt(j) || p.charAt(j) == '?')) {
                i++; j++;
            } else if (j < n && p.charAt(j) == '*') {
                match = i;
                asterisk = j++;
            } else if (asterisk != -1) {
                i = ++match;
                j = asterisk + 1;
            } else {
                return false;
            }
        }
        while (j < n && p.charAt(j) == '*') j++;
        return j == n;
    }
}

