    public boolean isMatch(String s, String p) {
        int m = s.length(), n = p.length();
        int i = 0, j = 0;
        boolean hasMatchingChars = false;
        boolean hasAsteriskAfterCurrentPosition = false;

        while (i < m && j < n) {
            if ((s.charAt(i) == p.charAt(j)) || (p.charAt(j) == '?')) {
                i++;
                j++;
                hasMatchingChars = true;
            } else if (j < n && p.charAt(j) == '*') {
                hasAsteriskAfterCurrentPosition = true;
                j++;
            } else if (hasAsteriskAfterCurrentPosition) {
                i++;
            } else {
                return false;
            }
        }

        while ((j < n) && (p.charAt(j) == '*')) {
            j++;
        }

        return hasMatchingChars || (!hasAsteriskAfterCurrentPosition && j == n);
    }
}

