public class Solution {
    public int uniquePathsWithObstacles(int[][] grid) {
        if (grid[0][0] == 1 || grid[m - 1][n - 1] == 1)
            return 0;

        for (int i = 0; i < m; ++i) {
            for (int j = 0; j < n; ++j) {
                if ((grid[i][j] != 0 && grid[i - 1][j] == 0) || 
                    (grid[i][j] != 0 && grid[i][j - 1] == 0)) {
                    grid[i][j] = 1;
                } else {
                    grid[i][j] = 0;
                }
            }
        }

        return grid[m - 1][n - 1];
    }
}

