public class Solution {
    public int minCut(String s) {
        int n = s.length();
        int[] dp = new int[n + 1];
        boolean[][] isPalindrome = new boolean[n][n];

        for (int i=0; i <= n; i++) {
            dp[i] = i - 1;
        }

        for (int j=1; j < n; j++) {
            for (int i=j; i >= 0; i--) {
                if (s.charAt(i) == s.charAt(j) && (j - i < 2 || isPalindrome[i + 1][j - 1])) {
                    isPalindrome[i][j] = true;
                    dp[j + 1] = Math.min(dp[j + 1], dp[i] + 1);
                }
            }
        }

        return dp[n];
    }
}

